INSERT OR IGNORE INTO spell(id, eid, key, name, description, spell_type, mana_cost, cost, game_id, version, created_by_sub, created_at, updated_at, deleted_at)
VALUES
  (1, 'e1000000-0000-0000-0000-000000000001', 'wh2_dlc09_spell_nehekhara_djafs_incantation_of_cursed_blades', 'Djaf''s Incantation of Cursed Blades', 'Imbued with the essence of the God of Death, the Nehekharans'' blades strike with supernatural force to harvest souls for Djaf.', 'wh_type_augment', 3, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (2, 'e1000000-0000-0000-0000-000000000002', 'wh2_dlc09_spell_nehekhara_djafs_incantation_of_cursed_blades_upgraded', 'Djaf''s Incantation of Cursed Blades Upgraded', 'Imbued with the essence of the God of Death, the Nehekharans'' blades strike with supernatural force to harvest souls for Djaf.', 'wh_type_augment', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (3, 'e1000000-0000-0000-0000-000000000003', 'wh2_dlc09_spell_nehekhara_nerus_incantation_of_protection', 'Neru''s Incantation of Protection', 'Sword-blows are mysteriously turned away as Ptra''s wife reaches out to shield Nehekhara''s warriors from evil.', 'wh_type_ward_save', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (4, 'e1000000-0000-0000-0000-000000000004', 'wh2_dlc09_spell_nehekhara_nerus_incantation_of_protection_upgraded', 'Neru''s Incantation of Protection Upgraded', 'Sword-blows are mysteriously turned away as Ptra''s wife reaches out to shield Nehekhara''s warriors from evil.', 'wh_type_ward_save', 10, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (5, 'e1000000-0000-0000-0000-000000000005', 'wh2_dlc09_spell_nehekhara_ptras_incantation_of_righteous_smiting', 'Ptra''s Incantation of Righteous Smiting', 'When the verses are spoken, a fierce light emanates from the Undead''s empty eye-sockets, enabling them to strike with supernatural speed and fury.', 'wh_type_augment', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (6, 'e1000000-0000-0000-0000-000000000006', 'wh2_dlc09_spell_nehekhara_ptras_incantation_of_righteous_smiting_upgraded', 'Ptra''s Incantation of Righteous Smiting Upgraded', 'When the verses are spoken, a fierce light emanates from the Undead''s empty eye-sockets, enabling them to strike with supernatural speed and fury.', 'wh_type_augment', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (7, 'e1000000-0000-0000-0000-000000000007', 'wh2_dlc09_spell_nehekhara_sakhmets_incantation_of_the_skullstorm', 'Sakhmet''s Incantation of the Skullstorm', 'A whirlwind of skulls tears across the battlefield, devouring all in its path in the Goddess of the Green Moon''s bitter, vindictive name.', 'wh_type_vortex', 10, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (8, 'e1000000-0000-0000-0000-000000000008', 'wh2_dlc09_spell_nehekhara_sakhmets_incantation_of_the_skullstorm_upgraded', 'Sakhmet''s Incantation of the Skullstorm Upgraded', 'A whirlwind of skulls tears across the battlefield, devouring all in its path in the Goddess of the Green Moon''s bitter, vindictive name.', 'wh_type_vortex', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (9, 'e1000000-0000-0000-0000-000000000009', 'wh2_dlc09_spell_nehekhara_usekhps_incantation_of_desiccation', 'Usekhp''s Incantation of Desiccation', 'Every syllable strips moisture and saps vitality from the bodies of Usekhp''s unfortunate victims.', 'wh_type_area_of_hexes', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (10, 'e1000000-0000-0000-0000-00000000000a', 'wh2_dlc09_spell_nehekhara_usekhps_incantation_of_desiccation_upgraded', 'Usekhp''s Incantation of Desiccation Upgraded', 'Every syllable strips moisture and saps vitality from the bodies of Usekhp''s unfortunate victims.', 'wh_type_area_of_hexes', 21, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (11, 'e1000000-0000-0000-0000-00000000000b', 'wh2_dlc09_spell_nehekhara_usirians_incantation_of_vengeance', 'Usirian''s Incantation of Vengeance', 'As the names of Usirian are invoked, skeletal hands burst forth from beneath the sand to drag the foe to their graves.', 'wh_type_direct_damage', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (12, 'e1000000-0000-0000-0000-00000000000c', 'wh2_dlc09_spell_nehekhara_usirians_incantation_of_vengeance_upgraded', 'Usirian''s Incantation of Vengeance Upgraded', 'As the names of Usirian are invoked, skeletal hands burst forth from beneath the sand to drag the foe to their graves.', 'wh_type_direct_damage', 13, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (13, 'e1000000-0000-0000-0000-00000000000d', 'wh2_dlc11_spell_beasts_transformation_of_kadon', 'Transformation of Kadon', 'Kadon was able to shift his shape to that of any monster, even a Varghulf. One day he found he could not change back...', 'wh_type_summon_unit', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (14, 'e1000000-0000-0000-0000-00000000000e', 'wh2_dlc11_spell_deep_denizens_of_the_deep', 'Denizens of the Deep', 'Some things should never rise above the waves or be seen by mortal eyes.', 'wh_type_summon_unit', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (15, 'e1000000-0000-0000-0000-00000000000f', 'wh2_dlc11_spell_deep_fog_of_the_damned', 'Fog of the Damned', '"They''ll never know how many we are in this fog… Attack!"', 'wh_type_area_of_hexes', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (16, 'e1000000-0000-0000-0000-000000000010', 'wh2_dlc11_spell_deep_fog_of_the_damned_upgraded', 'Fog of the Damned Upgraded', '"They''ll never know how many we are in this fog… Attack!"', 'wh_type_area_of_hexes', 11, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (17, 'e1000000-0000-0000-0000-000000000011', 'wh2_dlc11_spell_deep_ghost_ship', 'Vangheist''s Revenge', 'Every mariner has heard the tale of Vangheist, and now his restless spirit is summoned on board the Shadewraith to deliver a devastating broadside. ', 'wh_type_wind', 20, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (18, 'e1000000-0000-0000-0000-000000000012', 'wh2_dlc11_spell_deep_ghost_ship_upgraded', 'Vangheist''s Revenge Upgraded', 'Every mariner has heard the tale of Vangheist, and now his restless spirit is summoned on board the Shadewraith to deliver a devastating broadside. ', 'wh_type_wind', 26, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (19, 'e1000000-0000-0000-0000-000000000013', 'wh2_dlc11_spell_deep_krakens_pull', 'Kraken''s Pull', 'Few have the strength to break free once the Kraken has them within its horrid, betentacled grasp.', 'wh_type_vortex', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (20, 'e1000000-0000-0000-0000-000000000014', 'wh2_dlc11_spell_deep_krakens_pull_upgraded', 'Kraken''s Pull Upgraded', 'Few have the strength to break free once the Kraken has them within its horrid, betentacled grasp.', 'wh_type_vortex', 22, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (21, 'e1000000-0000-0000-0000-000000000015', 'wh2_dlc11_spell_deep_spiteful_shot', 'Spiteful Shot', 'Imbued with the purest hatred for the foe and all their ways, to better bring about an ignominious end.', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (22, 'e1000000-0000-0000-0000-000000000016', 'wh2_dlc11_spell_deep_spiteful_shot_upgraded', 'Spiteful Shot Upgraded', 'Imbued with the purest hatred for the foe and all their ways, to better bring about an ignominious end.', 'wh_type_augment', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (23, 'e1000000-0000-0000-0000-000000000017', 'wh2_dlc11_spell_deep_tidecall', 'Tidecall', 'The sea is summoned, and a great tide coalesces upon the battlefield to drench all those that oppose the caster.', 'wh_type_breath', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (24, 'e1000000-0000-0000-0000-000000000018', 'wh2_dlc11_spell_deep_tidecall_upgraded', 'Tidecall Upgraded', 'The sea is summoned, and a great tide coalesces upon the battlefield to drench all those that oppose the caster.', 'wh_type_breath', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (25, 'e1000000-0000-0000-0000-000000000019', 'wh2_dlc11_spell_vampires_drowned_dead', 'Drowned Dead', 'Drowned sailors are easily bound, for they remember their last voyage and many of their worldly duties.', 'wh_type_summon_unit', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (26, 'e1000000-0000-0000-0000-00000000001a', 'wh2_dlc11_spell_vampires_drowned_dead_upgraded', 'Drowned Dead Upgraded', 'Drowned sailors are easily bound, for they remember their last voyage and many of their worldly duties.', 'wh_type_summon_unit', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (27, 'e1000000-0000-0000-0000-00000000001b', 'wh2_dlc12_spell_kroak_deliverance_of_itza_1', 'Deliverance of Itza I', 'Mighty Lord Kroak spawns a small sun that, when it explodes, causes abject devastation… funnily enough.', 'wh_type_explosion', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (28, 'e1000000-0000-0000-0000-00000000001c', 'wh2_dlc12_spell_kroak_deliverance_of_itza_2', 'Deliverance of Itza II', 'Mighty Lord Kroak spawns a small sun that, when it explodes, causes abject devastation… funnily enough.', 'wh_type_explosion', 13, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (29, 'e1000000-0000-0000-0000-00000000001d', 'wh2_dlc12_spell_kroak_deliverance_of_itza_3', 'Deliverance of Itza III', 'Mighty Lord Kroak spawns a small sun that, when it explodes, causes abject devastation… funnily enough.', 'wh_type_explosion', 20, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (30, 'e1000000-0000-0000-0000-00000000001e', 'wh2_dlc14_spell_grey_seer_the_dreaded_thirteenth_spell_upgraded', 'The Dreaded Thirteenth Spell', 'The Curse of the Horned Rat is the dreaded 13th spell – the fabric of reality is torn and the Horned One’s children spill forth!', 'wh_type_explosion', 20, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (31, 'e1000000-0000-0000-0000-00000000001f', 'wh2_dlc14_spell_ruin_flensing_ruin', 'Flensing Ruin', 'Green ribbons of Warp-Energy tear the flesh from the target’s bones. It''s very nasty to behold – as nasty as it sounds, in fact – but far nastier, of course, if you''re the recipient…', 'wh_type_area_of_direct_damage', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (32, 'e1000000-0000-0000-0000-000000000020', 'wh2_dlc14_spell_ruin_flensing_ruin_upgraded', 'Flensing Ruin Upgraded', 'Green ribbons of Warp-Energy tear the flesh from the target’s bones. It''s very nasty to behold – as nasty as it sounds, in fact – but far nastier, of course, if you''re the recipient…', 'wh_type_area_of_direct_damage', 22, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (33, 'e1000000-0000-0000-0000-000000000021', 'wh2_dlc14_spell_stealth_armour_of_darkness', 'Armour of Darkness', 'Shadows solidify around the wearer''s body, protecting them from harm while simultaneously making them difficult to see, and therefore incapacitate.', 'wh_type_augment', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (34, 'e1000000-0000-0000-0000-000000000022', 'wh2_dlc14_spell_stealth_armour_of_darkness_upgraded', 'Armour of Darkness Upgraded', 'Shadows solidify around the wearer''s body, protecting them from harm while simultaneously making them difficult to see, and therefore incapacitate.', 'wh_type_area_of_augments', 11, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (35, 'e1000000-0000-0000-0000-000000000023', 'wh2_dlc14_spell_stealth_black_whirlwind', 'Black Whirlwind', 'This particularly unpleasant spell causes a putrid whirlwind of vile smoke, and alarmingly, stinging ashes to erupt around the target, leading to magical damage.', 'wh_type_vortex', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (36, 'e1000000-0000-0000-0000-000000000024', 'wh2_dlc14_spell_stealth_black_whirlwind_upgraded', 'Black Whirlwind Upgraded', 'This particularly unpleasant spell causes a putrid whirlwind of vile smoke, and alarmingly, stinging ashes to erupt around the target, leading to magical damage.', 'wh_type_vortex', 19, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (37, 'e1000000-0000-0000-0000-000000000025', 'wh2_dlc14_spell_stealth_brittle_bone', 'Brittle Bone', 'An ancient Skaven spell that enables the Wizard to weaken their target''s bones, causing different effects depending on who they are. All will suffer horribly, however.', 'wh_type_hex', 11, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (38, 'e1000000-0000-0000-0000-000000000026', 'wh2_dlc14_spell_stealth_brittle_bone_upgraded', 'Brittle Bone Upgrade', 'An ancient Skaven spell that enables the Wizard to weaken their target''s bones, causing different effects depending on who they are. All will suffer horribly, however.', 'wh_type_area_of_hexes', 18, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (39, 'e1000000-0000-0000-0000-000000000027', 'wh2_dlc14_spell_stealth_veil_of_shadows', 'Veil of Shadows', 'This pulsing, shadowy vortex barges into the target enemy, pushing them from the Wizard''s path with a blast of magical energy.', 'wh_type_vortex', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (40, 'e1000000-0000-0000-0000-000000000028', 'wh2_dlc14_spell_stealth_veil_of_shadows_upgraded', 'Veil of Shadows Upgraded', 'This pulsing, shadowy vortex barges into the target enemy, pushing them from the Wizard''s path with a blast of magical energy.', 'wh_type_vortex', 10, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (41, 'e1000000-0000-0000-0000-000000000029', 'wh2_dlc14_spell_stealth_warp_stars', 'Warp Stars', 'Deftly conjured and swiftly flung, the Skaven''s fiendish Warp throwing-stars are, like all their weird scientific advances, explicitly designed to cause maximum death.', 'wh_type_magic_missiles', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (42, 'e1000000-0000-0000-0000-00000000002a', 'wh2_dlc14_spell_stealth_warp_stars_upgraded', 'Warp Stars Upgraded', 'Deftly conjured and swiftly flung, the Skaven''s fiendish Warp throwing-stars are, like all their weird scientific advances, explicitly designed to cause maximum death.', 'wh_type_magic_missiles', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (43, 'e1000000-0000-0000-0000-00000000002b', 'wh2_dlc15_spell_beasts_transformation_of_kadon', 'Transformation of Kadon', 'Kadon was able to shift his shape to that of any monster, even an Eagle. One day he found he could not change back...', 'wh_type_summon_unit', 12, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (44, 'e1000000-0000-0000-0000-00000000002c', 'wh2_dlc17_spell_wild_mantle_of_ghorok_upgraded', 'Mantle of Ghorok Upgraded', 'Ghorok was a legendary Minotaur, ferocious as a storm. His spirit-mantle is terrible but dangerous to the bearer.', 'wh_type_augment', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (45, 'e1000000-0000-0000-0000-00000000002d', 'wh2_main_spell_dark_magic_bladewind', 'Bladewind', 'A swirling maelstrom of swords spin and slash their way across the battlefield in search of blood.', 'wh_type_vortex', 11, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (46, 'e1000000-0000-0000-0000-00000000002e', 'wh2_main_spell_dark_magic_bladewind_upgraded', 'Bladewind Upgraded', 'A swirling maelstrom of swords spin and slash their way across the battlefield in search of blood.', 'wh_type_vortex', 15, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (47, 'e1000000-0000-0000-0000-00000000002f', 'wh2_main_spell_dark_magic_chillwind', 'Chillwind', 'A freezing gale is conjured and sent to assail the target with ice and hail.', 'wh_type_wind', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
