  (95, 'e1000000-0000-0000-0000-00000000005f', 'wh3_dlc23_spell_hashut_curse_of_hashut_upgraded', 'Curse of Hashut Upgraded', 'Those who worship Hashut are accursed with a hideous malediction that can be directed at the foe through the darkest of dark sorceries.', 'wh_type_direct_damage', 15, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (96, 'e1000000-0000-0000-0000-000000000060', 'wh3_dlc23_spell_hashut_dark_subjugation', 'Dark Subjugation', 'The Father of Darkness is the God of Fire, Greed and Tyranny, whose malignant force utterly crushes the will of his adepts'' enemies.', 'wh_type_hex', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (97, 'e1000000-0000-0000-0000-000000000061', 'wh3_dlc23_spell_hashut_dark_subjugation_upgraded', 'Dark Subjugation Upgraded', 'The Father of Darkness is the God of Fire, Greed and Tyranny, whose malignant force utterly crushes the will of his adepts'' enemies.', 'wh_type_hex', 10, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (98, 'e1000000-0000-0000-0000-000000000062', 'wh3_dlc23_spell_hashut_flames_of_azgorh', 'Flames of Azgorh', 'The most terrible incantations, invoking fire and destruction, cause the ground to crack and extrude boiling magma. Things are about to get a little toasty!', 'wh_type_bombardment', 18, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (99, 'e1000000-0000-0000-0000-000000000063', 'wh3_dlc23_spell_hashut_flames_of_azgorh_upgraded', 'Flames of Azgorh Upgraded', 'The most terrible incantations, invoking fire and destruction, cause the ground to crack and extrude boiling magma. Things are about to get a little toasty!', 'wh_type_bombardment', 26, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (100, 'e1000000-0000-0000-0000-000000000064', 'wh3_dlc23_spell_hashut_hell_hammer', 'Hell Hammer', 'The power of Hashut manifests as a colossal, burning black hammer or bull''s head. Needless to say, anyone in its path is going to be flattened and reduced to ash.', 'wh_type_wind', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (101, 'e1000000-0000-0000-0000-000000000065', 'wh3_dlc23_spell_hashut_hell_hammer_upgraded', 'Hell Hammer Upgraded', 'The power of Hashut manifests as a colossal, burning black hammer or bull''s head. Needless to say, anyone in its path is going to be flattened and reduced to ash.', 'wh_type_wind', 20, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (102, 'e1000000-0000-0000-0000-000000000066', 'wh3_dlc24_spell_hags_curse_of_the_ancient_witch', 'Curse of the Ancient Witch', 'A hooded figure summoned by the Hag whispers words of terror, both mortal and immortal, to those who should never, ever have gone wandering in the woods…', 'wh_type_chain_hex', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (103, 'e1000000-0000-0000-0000-000000000067', 'wh3_dlc24_spell_hags_curse_of_the_ancient_witch_upgraded', 'Blessing of the Ancient Witch', 'For those fortunate enough to have the Hag’s favour, her hooded accomplice empowers arrows with the forest’s darkest intentions.', 'wh_type_chain_augment', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (104, 'e1000000-0000-0000-0000-000000000068', 'wh3_dlc24_spell_hags_cursed_cauldron', 'Cursed Cauldron', 'Conjured up from the Hag''s cauldron, spectral missiles shoot upwards to rain carnage down with indiscriminate devastation.', 'wh_type_bombardment', 18, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (105, 'e1000000-0000-0000-0000-000000000069', 'wh3_dlc24_spell_hags_cursed_cauldron_upgraded', 'Blessed Cauldron', 'Conjured up from the Hag''s cauldron, spectral missiles shoot upwards to rain carnage down, yet sparing the coven from harm.', 'wh_type_bombardment', 22, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (106, 'e1000000-0000-0000-0000-00000000006a', 'wh3_dlc24_spell_hags_malediction_of_madness', 'Malediction of Madness', 'A sudden rush of nightmarish visions floods the victim’s psyche, driving them to a fleeting madness that debilitates even the hardiest warrior.', 'wh_type_hex', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (107, 'e1000000-0000-0000-0000-00000000006b', 'wh3_dlc24_spell_hags_malediction_of_madness_upgraded', 'Incantation of Mania', 'On the Hag’s word, flashes of spectral moonlight reflect from blades and spearheads murderously thrust forth in a near-mindless bloodlust.', 'wh_type_augment', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (108, 'e1000000-0000-0000-0000-00000000006c', 'wh3_dlc24_spell_hags_the_forbidden_fens', 'The Forbidden Fens', 'The Hag beseeches ethereal forces deep underground to seep upwards and hamper the progress of her enemies, draining all momentum from them.', 'wh_type_area_of_hexes', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (109, 'e1000000-0000-0000-0000-00000000006d', 'wh3_dlc24_spell_hags_the_forbidden_fens_upgraded', 'Whispers in the Woods', 'Carried upon the Hag’s breath are incantations that emanate betwixt the trees, lightening the burden of those chosen to receive her blessings.', 'wh_type_area_of_augments', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (110, 'e1000000-0000-0000-0000-00000000006e', 'wh3_dlc24_spell_hags_vengeance_of_spirits', 'Vengeance of Spirits', 'The Hag channels a malevolent spirit into an enemy’s soul to saturate their being and gradually tear them to bloody, miniscule shreds from the inside out.', 'wh_type_area_of_direct_damage', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (111, 'e1000000-0000-0000-0000-00000000006f', 'wh3_dlc24_spell_hags_vengeance_of_spirits_upgraded', 'Omen of Spirits', 'The Hag invokes an ancient Sorcerer’s spirit, enthralling it to her bidding and sending it forth to siphon additional magical potency.', 'wh_type_augment_of_the_winds', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (112, 'e1000000-0000-0000-0000-000000000070', 'wh3_dlc24_spell_hags_witchbrew', 'Witchbrew', 'The Hag''s cauldron erupts in a bubbling crescendo, splashing its contents – and the Motherland’s boundless wrath – all over her hopeless enemies.', 'wh_type_breath', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (113, 'e1000000-0000-0000-0000-000000000071', 'wh3_dlc24_spell_hags_witchbrew_upgraded', 'Witchbroth', '"A Witchbroth a day keeps the gangrene away…"', 'wh_type_breath', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (114, 'e1000000-0000-0000-0000-000000000072', 'wh3_dlc27_spell_death_doom_and_darkness_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_death_doom_and_darkness_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_death_doom_and_darkness_upgraded}}', 'wh_type_hex', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (115, 'e1000000-0000-0000-0000-000000000073', 'wh3_dlc27_spell_death_spirit_leech_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_death_spirit_leech_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_death_spirit_leech_upgraded}}', 'wh_type_direct_damage', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (116, 'e1000000-0000-0000-0000-000000000074', 'wh3_dlc27_spell_death_the_purple_sun_of_xereus_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_death_the_purple_sun_of_xereus_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_death_the_purple_sun_of_xereus_upgraded}}', 'wh_type_vortex', 18, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (117, 'e1000000-0000-0000-0000-000000000075', 'wh3_dlc27_spell_fire_fireball_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_fire_fireball_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_fire_fireball_upgraded}}', 'wh_type_magic_missile', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (118, 'e1000000-0000-0000-0000-000000000076', 'wh3_dlc27_spell_fire_flame_storm_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_fire_flame_storm_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_fire_flame_storm_upgraded}}', 'wh_type_vortex', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (119, 'e1000000-0000-0000-0000-000000000077', 'wh3_dlc27_spell_fire_the_burning_head_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_fire_the_burning_head_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_fire_the_burning_head_upgraded}}', 'wh_type_wind', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (120, 'e1000000-0000-0000-0000-000000000078', 'wh3_dlc27_spell_heavens_chain_lightning', 'Chain Lightning', 'Lightning arcs across the battlefield, leaping from foe-to-foe with crackling fury until there are none left within the storm.', 'wh_type_chain_direct_damage', 14, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (121, 'e1000000-0000-0000-0000-000000000079', 'wh3_dlc27_spell_metal_final_transmutation_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_metal_final_transmutation_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_metal_final_transmutation_upgraded}}', 'wh_type_area_of_direct_damage', 17, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (122, 'e1000000-0000-0000-0000-00000000007a', 'wh3_dlc27_spell_metal_gehennas_golden_hounds_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_metal_gehennas_golden_hounds_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_metal_gehennas_golden_hounds_upgraded}}', 'wh_type_vortex', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (123, 'e1000000-0000-0000-0000-00000000007b', 'wh3_dlc27_spell_metal_searing_doom_summoned', '{{tr:unit_abilities_onscreen_name_wh_main_spell_metal_searing_doom_upgraded}}', '{{tr:unit_abilities_tooltip_text_wh_main_spell_metal_searing_doom_upgraded}}', 'wh_type_bombardment', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (124, 'e1000000-0000-0000-0000-00000000007c', 'wh3_dlc27_spell_mists_flensing_haar', 'Flensing Haar', 'Through callous interpretation of sea-faring sorcery, Cothiquan loremasters have learned to glaciate their quarry to lethargic helplessness.', 'wh_type_chain_hex', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (125, 'e1000000-0000-0000-0000-00000000007d', 'wh3_dlc27_spell_mists_flensing_haar_upgraded', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_flensing_haar}} Upgraded', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_flensing_haar}}', 'wh_type_chain_hex', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (126, 'e1000000-0000-0000-0000-00000000007e', 'wh3_dlc27_spell_mists_ladrielles_shroud', 'Ladrielle''s Shroud', 'A veil of vapour manifests around an ally, invigorating the beleaguered with glimpses of long-fallen kin. A portent of a mighty victory, tinged with the aftertaste of sadness.', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (127, 'e1000000-0000-0000-0000-00000000007f', 'wh3_dlc27_spell_mists_ladrielles_shroud_upgraded', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_ladrielles_shroud}} Upgraded', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_ladrielles_shroud}}', 'wh_type_augment', 9, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (128, 'e1000000-0000-0000-0000-000000000080', 'wh3_dlc27_spell_mists_mathlanns_spite', 'Mathlann’s Spite', 'The Sea God''s wrath fills your lungs with phantom brine, a taste of the fate that nearly claimed his Herald, Aislinn.', 'wh_type_hex', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (129, 'e1000000-0000-0000-0000-000000000081', 'wh3_dlc27_spell_mists_mathlanns_spite_upgraded', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_mathlanns_spite}} Upgraded', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_mathlanns_spite}}', 'wh_type_hex', 12, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (130, 'e1000000-0000-0000-0000-000000000082', 'wh3_dlc27_spell_mists_mistress_of_the_deeps', 'Mistress of the Deeps', 'Even amidst the glamour of pitched battle, the Asur’s enemies are haunted by the beguiling tones of the Oceanids'' song, moments before being utterly overwhelmed by them.', 'wh_type_summon_unit', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (131, 'e1000000-0000-0000-0000-000000000083', 'wh3_dlc27_spell_mists_the_writhing_mist', 'The Writhing Mist', 'A salt-scented mist rolls in across the battlefield, corroding the enemy''s resolve and shrouding the Asur with ethereal caress.', 'wh_type_area_of_augments', 10, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (132, 'e1000000-0000-0000-0000-000000000084', 'wh3_dlc27_spell_mists_the_writhing_mist_upgraded', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_the_writhing_mist}} Upgraded', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_the_writhing_mist}}', 'wh_type_area_of_augments', 14, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (133, 'e1000000-0000-0000-0000-000000000085', 'wh3_dlc27_spell_mists_walk_between_worlds', 'Walk Between Worlds', 'For a moment, one may tread immortal pathways by way of drifting in and out of reality.', 'wh_type_augment', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (134, 'e1000000-0000-0000-0000-000000000086', 'wh3_dlc27_spell_mists_walk_between_worlds_upgraded', '{{tr:unit_abilities_onscreen_name_wh3_dlc27_spell_mists_walk_between_worlds}}', '{{tr:unit_abilities_tooltip_text_wh3_dlc27_spell_mists_walk_between_worlds}}', 'wh_type_augment', 9, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (135, 'e1000000-0000-0000-0000-000000000087', 'wh3_main_spell_great_maw_bonecrusher', 'Bonecrusher', 'Stuffing a handful of bones into his mouth, the spellcaster crunches them up whilst cursing his foes, who are crushed by a giant fist which pounds them to dust.', 'wh_type_explosion', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (136, 'e1000000-0000-0000-0000-000000000088', 'wh3_main_spell_great_maw_bonecrusher_upgraded', 'Bonecrusher Upgraded', 'Stuffing a handful of bones into his mouth, the spellcaster crunches them up whilst cursing his foes, who are crushed by a giant fist which pounds them to dust.', 'wh_type_explosion', 15, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (137, 'e1000000-0000-0000-0000-000000000089', 'wh3_main_spell_great_maw_braingobbler', 'Braingobbler', 'The spellcaster chomps through a severed skull, gobbling up the brain and projecting the decapitated victim''s worst nightmares into enemies'' minds, sapping their will to fight on.', 'wh_type_hex', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (138, 'e1000000-0000-0000-0000-00000000008a', 'wh3_main_spell_great_maw_braingobbler_upgraded', 'Braingobbler Upgraded', 'The spellcaster chomps through a severed skull, gobbling up the brain and projecting the decapitated victim''s worst nightmares into enemies'' minds, sapping their will to fight on.', 'wh_type_hex', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (139, 'e1000000-0000-0000-0000-00000000008b', 'wh3_main_spell_great_maw_bullgorger', 'Bullgorger', 'Devouring the heart of a bull Rhinox or Mournfang, raw vitality is projected into the Great Maw, increasing the ferocity of the Ogres'' attacks.', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (140, 'e1000000-0000-0000-0000-00000000008c', 'wh3_main_spell_great_maw_bullgorger_upgraded', 'Bullgorger Upgraded', 'Devouring the heart of a bull Rhinox or Mournfang, raw vitality is projected into the Great Maw, increasing the ferocity of the Ogres'' attacks.', 'wh_type_augment', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (141, 'e1000000-0000-0000-0000-00000000008d', 'wh3_main_spell_great_maw_the_maw', 'The Maw', 'The Butcher can summon the power of the Great Maw itself, causing the ground beneath to split wide open and crush any foe trapped within it.', 'wh_type_explosion', 18, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (142, 'e1000000-0000-0000-0000-00000000008e', 'wh3_main_spell_great_maw_the_maw_upgraded', 'The Maw Upgraded', 'The Butcher can summon the power of the Great Maw itself, causing the ground beneath to split wide open and crush any foe trapped within it.', 'wh_type_explosion', 24, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (143, 'e1000000-0000-0000-0000-00000000008f', 'wh3_main_spell_great_maw_toothcracker', 'Toothcracker', 'By consuming a hunk of tooth-breaking granite, the spellcaster bestows the rock''s resilience and the sturdiness of the mountains themselves into his brethren.', 'wh_type_area_of_augments', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (144, 'e1000000-0000-0000-0000-000000000090', 'wh3_main_spell_great_maw_toothcracker_upgraded', 'Toothcracker Upgraded', 'By consuming a hunk of tooth-breaking granite, the spellcaster bestows the rock''s resilience and the sturdiness of the mountains themselves into his brethren.', 'wh_type_area_of_augments', 11, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (145, 'e1000000-0000-0000-0000-000000000091', 'wh3_main_spell_great_maw_trollguts', 'Trollguts', 'After downing the toxic and utterly repulsive innards of a Troll, the Ogres'' wounds seem to stitch themselves together before their enemies'' dumbfounded eyes.', 'wh_type_regeneration', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (146, 'e1000000-0000-0000-0000-000000000092', 'wh3_main_spell_great_maw_trollguts_upgraded', 'Trollguts Upgraded', 'After downing the toxic and utterly repulsive innards of a Troll, the Ogres'' wounds seem to stitch themselves together before their enemies'' dumbfounded eyes.', 'wh_type_regeneration', 26, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (147, 'e1000000-0000-0000-0000-000000000093', 'wh3_main_spell_ice_crystal_sanctuary', 'Crystal Sanctuary', 'Constructs are woven from the ice itself, sheltering Kislev''s courageous soldiers from the onslaught of their foes.', 'wh_type_augment', 8, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (148, 'e1000000-0000-0000-0000-000000000094', 'wh3_main_spell_ice_crystal_sanctuary_upgraded', 'Crystal Sanctuary Upgraded', 'Constructs are woven from the ice itself, sheltering Kislev''s courageous soldiers from the onslaught of their foes.', 'wh_type_area_of_augments', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (149, 'e1000000-0000-0000-0000-000000000095', 'wh3_main_spell_ice_death_frost', 'Death Frost', 'Warriors shiver and shake in a wintry grasp until the piercing cold reaches their hearts and, finally, they move no more.', 'wh_type_direct_damage', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (150, 'e1000000-0000-0000-0000-000000000096', 'wh3_main_spell_ice_death_frost_upgraded', 'Death Frost Upgraded', 'Warriors shiver and shake in a wintry grasp until the piercing cold reaches their hearts and, finally, they move no more.', 'wh_type_direct_damage', 15, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (151, 'e1000000-0000-0000-0000-000000000097', 'wh3_main_spell_ice_frost_blades', 'Frost Blades', 'Crackling magical energy envelopes the unit''s weapons, imbuing them with deadly new properties. Those impaled on these murderous blades will die in frozen agony.', 'wh_type_augment', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (152, 'e1000000-0000-0000-0000-000000000098', 'wh3_main_spell_ice_frost_blades_upgraded', 'Frost Blades Upgraded', 'Crackling magical energy envelopes the unit''s weapons, imbuing them with deadly new properties. Those impaled on these murderous blades will die in frozen agony.', 'wh_type_augment', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (153, 'e1000000-0000-0000-0000-000000000099', 'wh3_main_spell_ice_heart_of_winter', 'Heart of Winter', 'At one with the frozen plains and snowy tundra of Kislev, wherever this one goes, they bring the icy heart of the Motherland with them.', 'wh_type_area_of_direct_damage', 22, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (154, 'e1000000-0000-0000-0000-00000000009a', 'wh3_main_spell_ice_heart_of_winter_upgraded', 'Heart of Winter Upgraded', 'At one with the frozen plains and snowy tundra of Kislev, wherever this one goes, they bring the icy heart of the Motherland with them.', 'wh_type_area_of_direct_damage', 26, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (155, 'e1000000-0000-0000-0000-00000000009b', 'wh3_main_spell_ice_ice_maidens_kiss', 'Ice Maiden''s Kiss', 'The numbing kiss of winter is enough to have hoarfrost crystalise on the skin, chilling any creature to the bone.', 'wh_type_breath', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (156, 'e1000000-0000-0000-0000-00000000009c', 'wh3_main_spell_ice_ice_maidens_kiss_upgraded', 'Ice Maiden''s Kiss Upgraded', 'The numbing kiss of winter is enough to have hoarfrost crystalise on the skin, chilling any creature to the bone.', 'wh_type_breath', 10, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (157, 'e1000000-0000-0000-0000-00000000009d', 'wh3_main_spell_ice_ice_sheet', 'Ice Sheet', 'Such is the volume of snowfall that Kislev''s enemies must wade through that the air itself becomes a near-opaque wall of ice no gaze can penetrate.', 'wh_type_area_of_hexes', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (158, 'e1000000-0000-0000-0000-00000000009e', 'wh3_main_spell_nurgle_curse_of_the_leper', 'Curse of the Leper', 'As the caster speaks, his followers are blessed with resilience, whilst his enemies watch in horror as their limbs wither and drop off.', 'wh_type_augment', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (159, 'e1000000-0000-0000-0000-00000000009f', 'wh3_main_spell_nurgle_curse_of_the_leper_upgraded', 'Curse of the Leper Upgraded', 'As the caster speaks, his followers are blessed with resilience, whilst his enemies watch in horror as their limbs wither and drop off.', 'wh_type_augment', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (160, 'e1000000-0000-0000-0000-0000000000a0', 'wh3_main_spell_nurgle_fleshy_abundance', 'Fleshy Abundance', 'The most repulsive growth spurt imaginable occurs – the wobbling mounds of fat sealing wounds as soon as they are formed.', 'wh_type_regeneration', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (161, 'e1000000-0000-0000-0000-0000000000a1', 'wh3_main_spell_nurgle_fleshy_abundance_upgraded', 'Fleshy Abundance Upgraded', 'The most repulsive growth spurt imaginable occurs – the wobbling mounds of fat sealing wounds as soon as they are formed.', 'wh_type_area_of_regeneration', 28, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (162, 'e1000000-0000-0000-0000-0000000000a2', 'wh3_main_spell_nurgle_miasma_of_pestilence', 'Miasma of Pestilence', 'The most putrescent vapour fills the air, loosening lunches and bowels, and causing violent, crippling vomiting seizures in nearby foes.', 'wh_type_hex', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (163, 'e1000000-0000-0000-0000-0000000000a3', 'wh3_main_spell_nurgle_miasma_of_pestilence_upgraded', 'Miasma of Pestilence Upgraded', 'The most putrescent vapour fills the air, loosening lunches and bowels, and causing violent, crippling vomiting seizures in nearby foes.', 'wh_type_chain_hex', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (164, 'e1000000-0000-0000-0000-0000000000a4', 'wh3_main_spell_nurgle_pestilent_pustule', 'Blight Boil', 'This filthy, pulsating blister rapidly grows before suddenly bursting, showering the enemy with its disgusting fluid and all the maladies contained within.', 'wh_type_explosion', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
