  (166, 'e1000000-0000-0000-0000-0000000000a6', 'wh3_main_spell_nurgle_rancid_visitations', 'Rancid Visitations', 'The enemy is gifted the Plague Lord''s nightmarish necrosis, causing their skin to blacken and their internal organs to mulch.', 'wh_type_direct_damage', 15, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
