  (168, 'e1000000-0000-0000-0000-0000000000a8', 'wh3_main_spell_nurgle_stream_of_corruption', 'Stream of Corruption', 'A poisonous spurt of diseased gas and bile spews forth from the spellcaster''s diseased lungs, drenching the enemy in vile, choking pus.', 'wh_type_breath', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
