  (170, 'e1000000-0000-0000-0000-0000000000aa', 'wh3_main_spell_slaanesh_acquiescence', 'Acquiescence', 'The spellcaster''s corrupting touch puts their victims into a blissful, euphoric state for a short time, rendering them little able to move, let alone defend themselves.', 'wh_type_hex', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
