  (172, 'e1000000-0000-0000-0000-0000000000ac', 'wh3_main_spell_slaanesh_hysterical_frenzy', 'Hysterical Frenzy', 'The caster''s victims are engulfed by a torrent of unreasoning emotion, excruciating pain and blissful rapture, causing them to embark on a riotous, clawing rampage.', 'wh_type_augment', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
