  (174, 'e1000000-0000-0000-0000-0000000000ae', 'wh3_main_spell_slaanesh_lash_of_slaanesh', 'Lash of Slaanesh', 'The exquisite kiss of the Dark Prince''s three-tailed whip strikes the enemy with a delicious fury.', 'wh_type_breath', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (175, 'e1000000-0000-0000-0000-0000000000af', 'wh3_main_spell_slaanesh_lash_of_slaanesh_upgraded', 'Lash of Slaanesh Upgraded', 'The exquisite kiss of the Dark Prince''s three-tailed whip strikes the enemy with a delicious fury.', 'wh_type_breath', 9, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (176, 'e1000000-0000-0000-0000-0000000000b0', 'wh3_main_spell_slaanesh_pavane_of_slaanesh', 'Pavane of Slaanesh', 'Whistling one of Slaanesh’s perverse darkling dances causes the foe''s bones to jerk spasmodically until they break.', 'wh_type_direct_damage', 14, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
