  (178, 'e1000000-0000-0000-0000-0000000000b2', 'wh3_main_spell_slaanesh_phantasmagoria', 'Phantasmagoria', 'A complex sigil is performed, transfixing the enemy with a shifting array of hallucinatory images that disjoint and befuddle, inviting their deaths.', 'wh_type_area_of_hexes', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
