  (180, 'e1000000-0000-0000-0000-0000000000b4', 'wh3_main_spell_slaanesh_slicing_shards', 'Slicing Shards', 'A mirror forms in the sky only to be shattered into a myriad of deadly shards that lacerate the enemy below.', 'wh_type_bombardment', 12, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
