  (182, 'e1000000-0000-0000-0000-0000000000b6', 'wh3_main_spell_tempest_biting_wind', 'Biting Wind', 'The Winds of Magic are gathered into a mighty, freezing gale that slashes at the enemy with icy shards.', 'wh_type_wind', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
