  (206, 'e1000000-0000-0000-0000-0000000000ce', 'wh3_main_spell_yang_constellation_of_the_dragon', 'Constellation of the Dragon', 'Blazing starlight leaps from the Wizard’s fingertips, dancing and forming the constellation of the Dragon Emperor before descending upon the foe and exploding among their ranks. ', 'wh_type_explosion', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
