  (210, 'e1000000-0000-0000-0000-0000000000d2', 'wh3_main_spell_yang_jade_shield', 'Jade Shield', 'A blazing wind of light creates a potent barrier against harm, as well as invigorating all living things who shelter beneath its protection.', 'wh_type_ward_save', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
