  (212, 'e1000000-0000-0000-0000-0000000000d4', 'wh3_main_spell_yang_might_of_heaven_and_earth', 'Might of Heaven & Earth', 'Soldiers present are filled with the pure power of the Yang, which makes them stronger and more skilled, and their weapons blaze with celestial energy.', 'wh_type_augment', 10, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
