  (214, 'e1000000-0000-0000-0000-0000000000d6', 'wh3_main_spell_yang_stone_ground_stance', 'Stone Ground Stance', 'The Yang of all loyal Cathayans present comes to the fore, making even the humblest footsoldiers resolute and ready to fight and die where they stand.', 'wh_type_area_of_augments', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
