  (216, 'e1000000-0000-0000-0000-0000000000d8', 'wh3_main_spell_yang_wall_of_wind_and_fire', 'Wall of Wind & Fire', 'A vortex of fire and wind distorts everything seen through it and sows disorder and confusion among the enemy, leaving them vulnerable.', 'wh_type_wind', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
