  (218, 'e1000000-0000-0000-0000-0000000000da', 'wh3_main_spell_yin_ancestral_warriors', 'Ancestral Warriors', 'The warriors'' ancestors are summoned from the underworld, rising up to strike at the enemy with a furious assault before vanishing into the earth once more.', 'wh_type_summon_unit', 16, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
