  (232, 'e1000000-0000-0000-0000-0000000000e8', 'wh_dlc03_spell_beasts_panns_impenetrable_pelt', 'Pann''s Impenetrable Pelt', 'Calling upon the beast-spirits of the wild, the caster sheathes vulnerable flesh in unyielding fur and hide.', 'wh_type_augment', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
