  (235, 'e1000000-0000-0000-0000-0000000000eb', 'wh_dlc03_spell_beasts_the_amber_spear', 'The Amber Spear', 'Sounding a gnarled horn, the caster summons a glowing amber spear and hurls it at the foe with uncanny accuracy.', 'wh_type_magic_missile', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (236, 'e1000000-0000-0000-0000-0000000000ec', 'wh_dlc03_spell_beasts_the_amber_spear_upgraded', 'The Amber Spear Upgraded', 'Sounding a gnarled horn, the caster summons a glowing amber spear and hurls it at the foe with uncanny accuracy.', 'wh_type_magic_missile', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (237, 'e1000000-0000-0000-0000-0000000000ed', 'wh_dlc03_spell_beasts_the_curse_of_anraheir', 'The Curse of Anraheir', 'At the spellcaster''s command, nebulous nature spirits assail the foe, clawing with hands not nearly as insubstantial as they first appear.', 'wh_type_hex', 11, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (238, 'e1000000-0000-0000-0000-0000000000ee', 'wh_dlc03_spell_beasts_the_curse_of_anraheir_upgraded', 'The Curse of Anraheir Upgraded', 'At the spellcaster''s command, nebulous nature spirits assail the foe, clawing with hands not nearly as insubstantial as they first appear.', 'wh_type_hex', 14, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (239, 'e1000000-0000-0000-0000-0000000000ef', 'wh_dlc03_spell_beasts_transformation_of_kadon', 'Transformation of Kadon', 'Kadon was able to shift his shape to that of any monster, even a Manticore. One day he found he could not change back...', 'wh_type_summon_unit', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (240, 'e1000000-0000-0000-0000-0000000000f0', 'wh_dlc03_spell_beasts_wyssans_wildform', 'Wyssan''s Wildform', 'The spellcaster unleashes the beast within, using its fury to transform allies into bestial forms.', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (241, 'e1000000-0000-0000-0000-0000000000f1', 'wh_dlc03_spell_beasts_wyssans_wildform_upgraded', 'Wyssan''s Wildform Upgraded', 'The spellcaster unleashes the beast within, using its fury to transform allies into bestial forms.', 'wh_type_augment', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (242, 'e1000000-0000-0000-0000-0000000000f2', 'wh_dlc03_spell_wild_bray_scream', 'Bray-Scream', 'This spell unleashes a howling roar of such intensity that it mashes brains and bursts eyeballs.', 'wh_type_breath', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (243, 'e1000000-0000-0000-0000-0000000000f3', 'wh_dlc03_spell_wild_bray_scream_upgraded', 'Bray-Scream Upgraded', 'This spell unleashes a howling roar of such intensity that it mashes brains and bursts eyeballs.', 'wh_type_breath', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (244, 'e1000000-0000-0000-0000-0000000000f4', 'wh_dlc03_spell_wild_devolve', 'Devolve', 'The Bray-Shaman magnifies the savage and animalistic parts of the foe''s psyche until they are nothing more than growling beasts.', 'wh_type_hex', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (245, 'e1000000-0000-0000-0000-0000000000f5', 'wh_dlc03_spell_wild_devolve_upgraded', 'Devolve Upgraded', 'The Bray-Shaman magnifies the savage and animalistic parts of the foe''s psyche until they are nothing more than growling beasts.', 'wh_type_area_of_hexes', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (246, 'e1000000-0000-0000-0000-0000000000f6', 'wh_dlc03_spell_wild_mantle_of_ghorok', 'Mantle of Ghorok', 'Ghorok was a legendary Minotaur, ferocious as a storm. His spirit-mantle is terrible but dangerous to the bearer.', 'wh_type_augment', 9, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (247, 'e1000000-0000-0000-0000-0000000000f7', 'wh_dlc03_spell_wild_savage_dominion', 'Savage Dominion', 'The Bray-Shaman sends his mind winging into the wilds to possess a Cygor, then summons it to the battlefield.', 'wh_type_summon_unit', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (248, 'e1000000-0000-0000-0000-0000000000f8', 'wh_dlc03_spell_wild_traitor_kin', 'Traitor-Kin', 'The Bray-Shaman drives a spear of wrath into enemy hearts, unlocking the beast within and causing them to turn against their own.', 'wh_type_area_of_direct_damage', 11, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (249, 'e1000000-0000-0000-0000-0000000000f9', 'wh_dlc03_spell_wild_traitor_kin_upgraded', 'Traitor-Kin Upgraded', 'The Bray-Shaman drives a spear of wrath into enemy hearts, unlocking the beast within and causing them to turn against their own.', 'wh_type_area_of_direct_damage', 18, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (250, 'e1000000-0000-0000-0000-0000000000fa', 'wh_dlc03_spell_wild_viletide', 'Viletide', 'This spell calls to the creeping things of the undergrowth, sending a swarm of spiders, centipedes and slug-beetles onto the foe.', 'wh_type_explosion', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (251, 'e1000000-0000-0000-0000-0000000000fb', 'wh_dlc03_spell_wild_viletide_upgraded', 'Viletide Upgraded', 'This spell calls to the creeping things of the undergrowth, sending a swarm of spiders, centipedes and slug-beetles onto the foe.', 'wh_type_explosion', 10, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (252, 'e1000000-0000-0000-0000-0000000000fc', 'wh_dlc04_spell_death_doom_and_darkness_strigoi', 'Doom & Darkness', 'Spirits of the departed assail the Wizard’s foes, sapping their resolve and causing dread among their numbers.', 'wh_type_hex', 5, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (253, 'e1000000-0000-0000-0000-0000000000fd', 'wh_dlc04_spell_death_soulblight_strigoi', 'Soulblight', 'Harnessing the sickly power of Shyish, the Wizard weakens the foe''s will to survive the battle.', 'wh_type_area_of_hexes', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (254, 'e1000000-0000-0000-0000-0000000000fe', 'wh_dlc04_spell_death_spirit_leech_strigoi', 'Spirit Leech', 'The Wizard extends an ebon hand towards the chosen foe, leeching its spirit through tainted sorcery.', 'wh_type_direct_damage', 8, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (255, 'e1000000-0000-0000-0000-0000000000ff', 'wh_dlc04_spell_vampires_curse_of_years_helman', 'Curse of Years', 'The Wizard spits out an ancient curse, causing his enemies to age at an incredible rate - their hair turning white and skin shrivelling up.', 'wh_type_area_of_hexes', 10, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (256, 'e1000000-0000-0000-0000-000000000100', 'wh_dlc04_spell_vampires_gaze_of_nagash_helman', 'Gaze of Nagash', 'Bolts of Dark Magic leap from the caster’s eyes, withering flesh and blackening the bone beneath.', 'wh_type_magic_missiles', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (257, 'e1000000-0000-0000-0000-000000000101', 'wh_dlc04_spell_vampires_gaze_of_nagash_strigoi', 'Gaze of Nagash', 'Bolts of Dark Magic leap from the caster’s eyes, withering flesh and blackening the bone beneath.', 'wh_type_magic_missiles', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (258, 'e1000000-0000-0000-0000-000000000102', 'wh_dlc04_spell_vampires_invocation_of_nehek_helman', 'Invocation of Nehek', 'The caster intones the dread syllables once uttered by Nagash, restoring friendly targets.', 'wh_type_regeneration', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (259, 'e1000000-0000-0000-0000-000000000103', 'wh_dlc04_spell_vampires_invocation_of_nehek_strigoi', 'Invocation of Nehek', 'The caster intones the dread syllables once uttered by Nagash, restoring friendly targets.', 'wh_type_regeneration', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (260, 'e1000000-0000-0000-0000-000000000104', 'wh_dlc04_spell_vampires_raise_dead_helman', 'Awaken from the Grave', 'Helman Ghorst, the maudlin Necromancer, uses his dark knowledge of the black arts to raise the dead and bring them under his control.', 'wh_type_summon_unit', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
