  (264, 'e1000000-0000-0000-0000-000000000108', 'wh_dlc04_spell_vampires_vanhels_danse_macabre_helman', 'Vanhel''s Danse Macabre', 'Friendly targets are filled with magical energy, making them even more aggressive!', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (265, 'e1000000-0000-0000-0000-000000000109', 'wh_dlc04_spell_vampires_wind_of_death_helman', 'Wind of Death', 'The Wizard calls forth spectral winds that howl through the enemy ranks, tearing their souls from their bodies.', 'wh_type_wind', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (266, 'e1000000-0000-0000-0000-00000000010a', 'wh_dlc05_spell_life_awakening_of_the_wood', 'Awakening of the Wood', 'Trees live for thousands of years and have very long memories. When called to fight, centuries of pent-up wrath are unleashed.', 'wh_type_explosion', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
