  (273, 'e1000000-0000-0000-0000-000000000111', 'wh_dlc05_spell_life_regrowth', 'Regrowth', 'By speaking Druthandor''s name the Wizard is able to heal allies'' injuries much faster than by natural means.', 'wh_type_regeneration', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
