  (287, 'e1000000-0000-0000-0000-00000000011f', 'wh_dlc05_spell_shadow_the_enfeebling_foe', 'The Enfeebling Foe', 'When cast, this spell enfeebles enemy minds; they feel the crushing weight of reality bearing down upon them.', 'wh_type_hex', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
