  (289, 'e1000000-0000-0000-0000-000000000121', 'wh_dlc05_spell_shadow_the_penumbral_pendulum', 'The Penumbral Pendulum', 'A spectral pendulum is summoned by the Wizard. On command, it swings, razor sharp and with lethal speed, through the foe.', 'wh_type_wind', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
