  (295, 'e1000000-0000-0000-0000-000000000127', 'wh_dlc08_spell_death_aspect_of_the_dreadknight_arzik', 'Aspect of the Dread Knight', 'An invisible aura of horror surrounds the Wizard’s allies. Only the bravest foes now stand before them.', 'wh_type_augment', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (296, 'e1000000-0000-0000-0000-000000000128', 'wh_dlc08_spell_death_soulblight_arzik', 'Soulblight', 'Harnessing the sickly power of Shyish, the Wizard weakens the foe''s will to survive the battle.', 'wh_type_area_of_hexes', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (297, 'e1000000-0000-0000-0000-000000000129', 'wh_dlc08_spell_death_the_fate_of_bjuna_arzik', 'The Fate of Bjuna', 'Following the fate of the unsmiling warrior, Bjuna, the targets of the caster’s ire will laugh themselves to death.', 'wh_type_direct_damage', 22, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (298, 'e1000000-0000-0000-0000-00000000012a', 'wh_dlc08_spell_fire_fireball_kihar', 'Fireball', 'The Wizard conjures a boiling ball of magical flame and hurls it at a nearby foe.', 'wh_type_magic_missile', 5, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (299, 'e1000000-0000-0000-0000-00000000012b', 'wh_dlc08_spell_fire_flaming_sword_of_rhuin_kihar', 'Flaming Sword of Rhuin', 'The Wizard ensorcels allied weapons, making them burn with a savage fire. The targets of the spell are augmented with superior flaming blades.', 'wh_type_area_of_augments', 7, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (300, 'e1000000-0000-0000-0000-00000000012c', 'wh_dlc08_spell_metal_final_transmutation_arzik', 'Final Transmutation', 'The Wizard unleashes a hail of magical energy, transmuting his foes into Unliving golden statues.', 'wh_type_area_of_direct_damage', 17, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (301, 'e1000000-0000-0000-0000-00000000012d', 'wh_dlc08_spell_metal_gehennas_golden_hounds_arzik', 'Gehenna''s Golden Hounds', 'Blowing on a glimmering golden whistle, the Wizard summons the spirit of Gehenna’s metal hounds to hunt down his prey.   ', 'wh_type_vortex', 8, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (302, 'e1000000-0000-0000-0000-00000000012e', 'wh_dlc08_spell_metal_plague_of_rust_kihar', 'Plague of Rust', 'The enemy target''s armour begins to rust, disappearing in clouds of tiny flakes and weakening his defensive abilities.', 'wh_type_hex', 4, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (303, 'e1000000-0000-0000-0000-00000000012f', 'wh_dlc08_spell_metal_searing_doom_arzik', 'Searing Doom', 'A spray of sizzling silver slivers rain from the sky to impale the caster''s enemy.', 'wh_type_bombardment', 6, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (304, 'e1000000-0000-0000-0000-000000000130', 'wh_dlc08_spell_metal_transmutation_of_lead_kihar', 'Transmutation of Lead', 'The enemies’ weapons become heavy, cumbersome, and almost impossible to wield in battle.', 'wh_type_area_of_hexes', 11, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (305, 'e1000000-0000-0000-0000-000000000131', 'wh_dlc08_spell_shadow_pit_of_shades_kihar', 'Pit of Shades', 'The spellcaster opens a vortex leading into the Pit. Anything caught within it will be lost forever.', 'wh_type_vortex', 15, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (306, 'e1000000-0000-0000-0000-000000000132', 'wh_dlc08_spell_shadow_the_penumbral_pendulum_kihar', 'The Penumbral Pendulum', 'A spectral pendulum is summoned by the Wizard. On command, it swings, razor sharp and with lethal speed, through the foe.', 'wh_type_wind', 12, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
  (307, 'e1000000-0000-0000-0000-000000000133', 'wh_main_spell_big_waaagh_brain_bursta', 'Brain Bursta', 'Projecting violence in a mental wave, the Shaman glowers at his target and lets loose a bolt of brain-melting force.', 'wh_type_explosion', 7, 100, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
