  (311, 'e1000000-0000-0000-0000-000000000137', 'wh_main_spell_big_waaagh_ere_we_go', '''Ere We Go', 'As the Shaman chants, he leaks fighty-energy, boosting the fierceness and prowess of friendly units nearby.', 'wh_type_area_of_augments', 11, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
