  (331, 'e1000000-0000-0000-0000-00000000014b', 'wh_main_spell_fire_flame_storm', 'Flame Storm', 'Conjured by a Bright Wizard or Chaos Sorcerer, a column of churning fire erupts from the battlefield, causing much destruction!    ', 'wh_type_vortex', 13, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
