  (335, 'e1000000-0000-0000-0000-00000000014f', 'wh_main_spell_fire_piercing_bolts_of_burning', 'Piercing Bolts of Burning', 'Focusing all his mystical might, the Pyromancer strikes the foe with a flurry of incandescent missiles.', 'wh_type_bombardment', 10, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
