  (339, 'e1000000-0000-0000-0000-000000000153', 'wh_main_spell_heavens_chain_lightning', 'Chain Lightning', 'Lightning arcs across the battlefield, leaping from foe-to-foe with crackling fury until there are none left within the storm.', 'wh_type_vortex', 14, 200, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
