  (366, 'e1000000-0000-0000-0000-00000000016e', 'wh_main_spell_lil_waaagh_gorkll_fix_it', 'Gork''ll Fix It', 'The Shaman points a bony finger at a nearby enemy, cursing them in the name of Gork.', 'wh_type_hex', 6, 150, 1, 1, 'f0ce7395-a57f-41e9-ade0-fd13bafc058f', STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), STRFTIME('%Y-%m-%dT%H:%M:%fZ','now'), null),
